// Ordena as mensagens pela data
items.sort((a, b) =>
  new Date(a.json.created_at).getTime() - new Date(b.json.created_at).getTime()
);

function formatarData(isoDate) {
  const d = new Date(isoDate);
  const dia = String(d.getDate()).padStart(2, "0");
  const mes = String(d.getMonth() + 1).padStart(2, "0");
  const ano = d.getFullYear();
  return `${dia}/${mes}/${ano}`;
}

const historico = [];

for (const item of items) {
  const row = item.json;
  const data = formatarData(row.created_at);

  if (row.mensagem_usuario?.trim()) {
    historico.push({
      autor: "Usuário",
      mensagem: row.mensagem_usuario.trim(),
      data
    });
  }

  if (row.mensagem_agente?.trim()) {
    historico.push({
      autor: "Agente",
      mensagem: row.mensagem_agente.trim(),
      data
    });
  }
}

// =====================================================
// NOVO TRECHO → Conta mensagens seguidas do agente
// =====================================================
let qtd_mensagens_sem_resposta = 0;

for (let i = historico.length - 1; i >= 0; i--) {
  if (historico[i].autor === "Agente") {
    qtd_mensagens_sem_resposta++;
  } else {
    break; // usuário falou → reset
  }
}
// =====================================================

return [
  {
    json: {
      historico_conversa: historico,
      qtd_mensagens_sem_resposta
    }
  }
];

return items.map(item => {
  let raw = item.json.output || "";
  let cleaned = raw;

  // 1. Remove blocos de código tipo ```json ... ```
  cleaned = cleaned.replace(/```json/gi, "");
  cleaned = cleaned.replace(/```/g, "");

  cleaned = cleaned.trim();

  let respostaIA = {};

  // 2. Parse seguro
  try {
    respostaIA = JSON.parse(cleaned);
  } catch (e) {
    respostaIA = {
      template: "erro",
      var_1: item.json.name || "",
      var_2: item.json.var_2 || "",
      telefone: item.json.telefone || "",
    };
  }

  // 3. Mapa de templates oficiais (Reagendamento No Show — IA Luana)
  const templates = {
    reagendar_primeiro_contato:
      "Oi *{{1}}*! Tudo bem? \n\nVi que tínhamos uma conversa marcada para *{{2}}*, mas não conseguimos nos falar.\n\nQuer reagendar em um horário que fique melhor pra você?",

    reagendar_reforco_convite:
      "Fala *{{1}}*! \n\n Só pra não deixar passar... Ficou pendente nosso papo do dia *{{2}}*. \n\n Imagino que a rotina deve estar corrida. Quer que eu te mande algumas opções pra gente tentar de novo?",

    reagendar_continuar_fluxo:
      "Opa *{{1}}*, tudo bem?\n\nPassando aqui pra dar sequência na nossa conversa que seria em *{{2}}*.\n\nQuer que eu te mande algumas opções de horário pra reagendarmos?",

    reagendar_ultimo_convite:
      "Olá *{{1}}*! \n\n Ainda faz sentido a gente remarcar aquela conversa de *{{2}}*? \n\n Se preferir, me avisa qual o melhor momento pra você que eu ajusto minha agenda aqui.",

    reengajamento_suave_noshow:
      "Oi *{{1}}*! Tudo bem?\n\nComo não consegui retorno sobre reagendar nossa conversa, quis confirmar se ainda tem interesse em batermos esse papo.\n\nPosso te mandar alguns horários?",

    reengajamento_novo_angulo_noshow:
      "Fala *{{1}}*! \n\n Sei que o dia a dia engole a gente às vezes, rsrs. O papo de *{{2}}* acabou ficando pra trás, mas se quiser garantir a vaga, é só me dar um alô que a gente resolve rápido.",

    ping_simples_1:
      "Oi, tudo bem por aí?",

    ping_simples_2:
      "Oi {{1}}, tem um minutinho?",

    ping_nome_1:
      "Opa {{1}}, tudo tranquilo?",

    ping_retorno_1:
      "Oi, pode me dar um retorno quando der?",

    ping_retorno_2:
      "Oii, me chama quando puder?",

    despedida_encerramento_reagendamento:
      "Oi *{{1}}*, como não tivemos um retorno recente, vou encerrar nossa conversa por aqui.\n\nSe quiser reagendar mais pra frente, estarei à disposição pra te ajudar, combinado?"
  };

  const templateName = respostaIA.template;
  const textoTemplate = templates[templateName] || "Template não encontrado.";

  // 4. Substitui {{1}} e {{2}} pelos valores das variáveis
  const mensagemFinal = textoTemplate
    .replace("{{1}}", respostaIA.var_1 || "")
    .replace("{{2}}", respostaIA.var_2 || "");

  // 5. Retorno final do node
  return {
    json: {
      ...respostaIA,
      mensagem_template: mensagemFinal
    }
  };
});

const templates = {
  reagendar_primeiro_contato:
    "Oi *{{1}}*! Tudo bem? \n\nVi que tínhamos uma conversa marcada para *{{2}}*, mas não conseguimos nos falar.\n\nQuer reagendar em um horário que fique melhor pra você?",

  reagendar_reforco_convite:
    "Oi *{{1}}*! Tudo bem?\n\nVerifiquei aqui nossa conversa que seria em *{{2}}*.\nFoi uma pena não conseguirmos falar naquele dia \n\nTem algum outro horário que te encaixa melhor?",

  reagendar_continuar_fluxo:
    "Opa *{{1}}*, tudo bem?\n\nPassando aqui pra dar sequência na nossa conversa que seria em *{{2}}*.\n\nQuer que eu te mande algumas opções de horário pra reagendarmos?",

  reagendar_ultimo_convite:
    "Oi *{{1}}*! Tudo bem?\n\nGostaria de saber se podemos reagendar aquele papo que estava marcado pra *{{2}}*.\n\nCaso sim, posso ajustar no melhor horário pra você. O que acha?",

  reengajamento_suave_noshow:
    "Oi *{{1}}*! Tudo bem?\n\nComo não consegui retorno sobre reagendar nossa conversa, quis confirmar se ainda tem interesse em batermos esse papo.\n\nPosso te mandar alguns horários?",

  reengajamento_novo_angulo_noshow:
    "Oi *{{1}}*! \n\nSei que sua rotina pode estar corrida, mas queria ver se ainda faz sentido reagendarmos aquele bate-papo que seria em *{{2}}*.\nPodemos só ajustar o horário que já resolve, quer que eu veja algumas opções pra você?",

  ping_simples_1:
    "Oi, tudo bem por aí?",

  ping_simples_2:
    "Oi {{1}}, tem um minutinho?",

  ping_nome_1:
    "Opa {{1}}, tudo tranquilo?",

  ping_retorno_1:
    "Oi, pode me dar um retorno quando der?",

  ping_retorno_2:
    "Oii, me chama quando puder?",

  despedida_encerramento_reagendamento:
    "Oi *{{1}}*, como não tivemos um retorno recente, vou encerrar nossa conversa por aqui.\n\nSe quiser reagendar mais pra frente, estarei à disposição pra te ajudar, combinado?"
};

// --- PROCESSADOR ---
const entrada = items[0].json;
const textoTemplate = templates[entrada.template];

if (!textoTemplate) {
  return [{ json: { erro: "Template não encontrado" } }];
}

// Detecta automaticamente quais variáveis existem no template
const possuiVar1 = textoTemplate.includes("{{1}}");
const possuiVar2 = textoTemplate.includes("{{2}}");

// Monta estrutura da API do WhatsApp
const body = {
  messaging_product: "whatsapp",
  to: String(entrada.telefone),
  type: "template",
  template: {
    name: entrada.template,
    language: { code: "pt_BR" }
  }
};

// Adiciona parâmetros dinamicamente
const parametros = [];
if (possuiVar1 && entrada.var_1) parametros.push({ type: "text", text: entrada.var_1 });
if (possuiVar2 && entrada.var_2) parametros.push({ type: "text", text: entrada.var_2 });

if (parametros.length > 0) {
  body.template.components = [
    {
      type: "body",
      parameters: parametros
    }
  ];
}

// --- RETORNO FINAL ---
return [
  {
    json: {
      resultado: body
    }
  }
];

